proof fn phi_1_inv_allows_empty_arch()
    ensures
        exists|a: Arch| a.inv() && a.layers.len() == 0,
{
    let a = Arch { layers: Seq::empty() };
    assert(a.inv());
}

proof fn phi_2_inv_allows_unit_num_entries()
    ensures
        exists|a: Arch| a.inv() && a.layers.len() >= 2 &&
            (forall|i: nat| i < a.layers.len() ==> a.num_entries(i) == 1),
{
    let l = ArchLayer { entry_size: 1, num_entries: 1 };
    let a = Arch { layers: seq![l, l] };
    assert(a.entry_size(0) == 1);
    assert(a.num_entries(1) == 1);
    assert(a.entry_size_is_next_layer_size(0));
    assert(a.entry_size_is_next_layer_size(1));
    assert(a.inv());
}

proof fn phi_3_inv_allows_equal_consecutive_entry_sizes()
    ensures
        exists|a: Arch| a.inv() && a.layers.len() >= 2 &&
            a.entry_size(0) == a.entry_size(1),
{
    let l = ArchLayer { entry_size: 1, num_entries: 1 };
    let a = Arch { layers: seq![l, l] };
    assert(a.entry_size_is_next_layer_size(0));
    assert(a.entry_size_is_next_layer_size(1));
    assert(a.inv());
}

proof fn phi_5_inv_allows_top_entry_size_one()
    ensures
        exists|a: Arch| a.inv() && a.layers.len() == X86_NUM_LAYERS &&
            a.entry_size(0) == 1,
{
    let l = ArchLayer { entry_size: 1, num_entries: 1 };
    let a = Arch { layers: seq![l, l, l, l] };
    assert(a.entry_size_is_next_layer_size(0));
    assert(a.entry_size_is_next_layer_size(1));
    assert(a.entry_size_is_next_layer_size(2));
    assert(a.entry_size_is_next_layer_size(3));
    assert(a.inv());
}
